```javascript
// Results from Coveo:
// Index 0: epprice = 0,   epcurrency = "USD"  ← shown FIRST on page
// Index 1: epprice = 250, epcurrency = "GBP"
// Index 2: epprice = 0,   epcurrency = "USD"

